-- ============================================================
--  RESET + IMPORT — Congresso 2026
--  APAGA dados de teste (presencas, participantes, palestras) e
--  recarrega as 23 sessoes reais + 3.603 participantes.
--  NAO mexe em validadores (logins) nem email_config (template).
--  Rode o arquivo inteiro no SQL Editor do Supabase.
-- ============================================================

-- 1) limpa na ordem das foreign keys (presencas -> participantes -> palestras)
delete from presenca.presencas;
delete from presenca.participantes;
delete from presenca.palestras;

-- 2) recria sessoes + participantes
-- ============================================================
--  IMPORT COMPLETO Congresso 2026 (rode este arquivo inteiro).
--  1) cria/atualiza as 23 sessoes em presenca.palestras
--  2) insere os 3.603 participantes (a FK ja fica satisfeita).
-- ============================================================

-- ============================================================
--  Sessões do Congresso 2026 -> tabela presenca.palestras
--  id = palestra_id usado em participantes (ex.: MOCHILA_M, EJA_N).
--  Fonte dos locais/horários: documento oficial LOCAIS E PALESTRANTES.
--  Rode no SQL Editor do Supabase (projeto do gom).
-- ============================================================

alter table presenca.palestras add column if not exists local     text;
alter table presenca.palestras add column if not exists endereco  text;
alter table presenca.palestras add column if not exists periodo   text;
alter table presenca.palestras add column if not exists hora      text;

-- Upsert das 23 sessões (cria ou atualiza; preserva presencas/participantes).

-- ---------- PARTICIPANTES ----------
-- Import participantes Congresso 2026 -> presenca.participantes
-- PRE-REQUISITO: rodar antes db/adicionar-local-sessoes.sql.

alter table presenca.participantes add column if not exists codigo_funcional text;
alter table presenca.participantes add column if not exists origem           text;
alter table presenca.participantes add column if not exists unidade          text;

-- (opcional) recomecar do zero:
-- delete from presenca.presencas;
-- delete from presenca.participantes;

on conflict (token) do update set nome=excluded.nome, email=excluded.email, cpf=excluded.cpf, palestra_id=excluded.palestra_id, codigo_funcional=excluded.codigo_funcional, origem=excluded.origem, unidade=excluded.unidade;

on conflict (token) do update set nome=excluded.nome, email=excluded.email, cpf=excluded.cpf, palestra_id=excluded.palestra_id, codigo_funcional=excluded.codigo_funcional, origem=excluded.origem, unidade=excluded.unidade;

